[
  {
    "path": "infra/observability/prometheus/prometheus.yml",
    "line": "  - job_name: redis",
    "severity": "high",
    "message": "New prod runtime surface `redis` (added to services.yml for staging/prod) gets a scrape job and a redis-exporter, but has NO alert rule. infra/observability/prometheus/alerts/ contains only postgres.yml, otel-collector.yml, and app.yml. Postgres ships PostgresDown + connection alerts; redis ships nothing — so a prod redis outage fires no alert and silently breaks Celery/cache that depend on it. A new prod data store with zero alerting is a real observability gap.",
    "suggestion": "Add infra/observability/prometheus/alerts/redis.yml (e.g. RedisDown on `redis_up == 0` for 1m, plus memory/eviction/connection warnings) and ensure it is picked up by the prometheus rule_files glob, mirroring postgres.yml."
  },
  {
    "path": "infra/observability/prometheus/prometheus.yml",
    "line": "  - job_name: redis",
    "severity": "medium",
    "message": "The new redis scrape job has no matching Grafana dashboard. infra/observability/grafana/dashboards/ contains only postgres.json, otel-collector.json, and app.json — there is no redis.json. The redis surface is now scraped (redis-exporter:9121) but never visualized, so the collected metrics are not usable for operators.",
    "suggestion": "Add infra/observability/grafana/dashboards/redis.json (uptime, used memory vs maxmemory, connected clients, ops/sec, keyspace hits/misses, evictions) provisioned via the existing dashboards provider, matching the postgres dashboard pattern."
  }
]
